import{_ as e,o as a,c as l,a2 as n}from"./chunks/framework.BQ1gajhD.js";const y=JSON.parse('{"title":"西洋楼建筑群","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/yuanmingyuan/xiyang-lou.md","filePath":"landmarks/yuanmingyuan/xiyang-lou.md","lastUpdated":1784720050000}'),r={name:"landmarks/yuanmingyuan/xiyang-lou.md"};function i(d,t,s,o,g,h){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="西洋楼建筑群" tabindex="-1">西洋楼建筑群 <a class="header-anchor" href="#西洋楼建筑群" aria-label="Permalink to &quot;西洋楼建筑群&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1555085634-7b3d72893f38?w=1200&amp;q=80" alt="西洋楼遗址"></p><blockquote><p>在东方园林的心脏地带，曾矗立着一座巴洛克式的幻境——它是乾隆皇帝眼中的&quot;西洋奇器&quot;，也是中西文明相遇的石头证词。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>西洋楼位于长春园北部狭长地带，是圆明园三园中<strong>唯一的西式景区</strong>，南北宽约百米，东西绵延约750米，占地约<strong>6万平方米</strong>。乾隆十二年至二十四年（1747-1759年）间，由意大利传教士郎世宁、法国传教士蒋友仁等西洋匠师设计监造，中国工匠施工建成。</p><p>景区以<strong>巴洛克风格</strong>为基调，又大量融入中式纹样与琉璃构件，是18世纪东西方建筑艺术罕见的大规模融合实例。全景区自西向东由谐奇趣、蓄水楼、万花阵、养雀笼、方外观、海晏堂、大水法、观水法、远瀛观、线法山、线法墙等十余组建筑与园林构成，以<a href="/beijing-travel-guide/landmarks/yuanmingyuan/dashuifa.html">大水法</a>喷泉群为高潮。</p><p>1860年遭焚劫后，西洋楼因石构居多而残迹留存最多，成为今日圆明园遗址的核心展区。这片绵延的石砌废墟，也是中国人最熟悉的圆明园形象。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>建造年代</strong></td><td style="text-align:left;">乾隆十二年至二十四年（1747-1759年）</td></tr><tr><td style="text-align:left;"><strong>占地面积</strong></td><td style="text-align:left;">约6万平方米，东西长约750米</td></tr><tr><td style="text-align:left;"><strong>设计监造</strong></td><td style="text-align:left;">郎世宁、蒋友仁等西洋传教士，中国工匠施工</td></tr><tr><td style="text-align:left;"><strong>建筑风格</strong></td><td style="text-align:left;">巴洛克为主，中西合璧</td></tr><tr><td style="text-align:left;"><strong>门票</strong></td><td style="text-align:left;">遗址区15元（含大水法、海晏堂等全部景点）</td></tr><tr><td style="text-align:left;"><strong>现状</strong></td><td style="text-align:left;">木构尽毁，石构残迹留存；万花阵为1989年复建</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><h3 id="景区建筑一览" tabindex="-1">景区建筑一览 <a class="header-anchor" href="#景区建筑一览" aria-label="Permalink to &quot;景区建筑一览&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:center;">建成</th><th style="text-align:left;">功能</th><th style="text-align:left;">现状</th></tr></thead><tbody><tr><td style="text-align:left;">谐奇趣</td><td style="text-align:center;">1751年</td><td style="text-align:left;">音乐喷泉、演奏西洋乐器</td><td style="text-align:left;">残基遗址</td></tr><tr><td style="text-align:left;">蓄水楼</td><td style="text-align:center;">1751年前后</td><td style="text-align:left;">全区喷泉供水系统</td><td style="text-align:left;">残基遗址</td></tr><tr><td style="text-align:left;">万花阵</td><td style="text-align:center;">1751年前后</td><td style="text-align:left;">花园迷宫、中秋赏灯</td><td style="text-align:left;">1989年复建</td></tr><tr><td style="text-align:left;">养雀笼</td><td style="text-align:center;">约1754年</td><td style="text-align:left;">饲养孔雀等珍禽</td><td style="text-align:left;">石券门残迹</td></tr><tr><td style="text-align:left;">方外观</td><td style="text-align:center;">约1759年</td><td style="text-align:left;">容妃（香妃）礼拜处</td><td style="text-align:left;">残基遗址</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/yuanmingyuan/haiyan-tang.html">海晏堂</a></td><td style="text-align:center;">1759年</td><td style="text-align:left;">兽首喷泉、宴请外藩</td><td style="text-align:left;">残墙台阶</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/yuanmingyuan/dashuifa.html">大水法</a></td><td style="text-align:center;">1759年</td><td style="text-align:left;">欧式喷泉主景</td><td style="text-align:left;">残柱矗立</td></tr><tr><td style="text-align:left;">观水法</td><td style="text-align:center;">1759年</td><td style="text-align:left;">皇帝观喷泉宝座</td><td style="text-align:left;">石屏宝座残迹</td></tr><tr><td style="text-align:left;">远瀛观</td><td style="text-align:center;">1759年</td><td style="text-align:left;">观景高台</td><td style="text-align:left;">石门残基</td></tr><tr><td style="text-align:left;">线法山、线法墙</td><td style="text-align:center;">约1759年</td><td style="text-align:left;">透视画景装置</td><td style="text-align:left;">山形遗址</td></tr></tbody></table><h3 id="谐奇趣与蓄水楼" tabindex="-1">谐奇趣与蓄水楼 <a class="header-anchor" href="#谐奇趣与蓄水楼" aria-label="Permalink to &quot;谐奇趣与蓄水楼&quot;">​</a></h3><p><strong>谐奇趣</strong>是西洋楼最早建成的建筑，楼前有海棠形喷水池，池中铜鹅、铜羊喷水，楼内陈设西洋乐器，是演奏欧洲音乐之处。其北的<strong>蓄水楼</strong>为二层楼式蓄水池，以铜板焊接盛水180余吨，靠水力机械将水提升至高处，再凭重力供给全区喷泉——它是整座西洋楼水法系统的&quot;心脏&quot;。</p><h3 id="万花阵-黄花阵" tabindex="-1">万花阵（黄花阵） <a class="header-anchor" href="#万花阵-黄花阵" aria-label="Permalink to &quot;万花阵（黄花阵）&quot;">​</a></h3><p><strong>万花阵</strong>是一座仿欧式园林的<strong>花园迷宫</strong>，阵墙高约1.2米，以雕花砖墙盘成回环往复的迷阵，中心设圆形凉亭。</p><p>中秋之夜，皇帝坐于中心亭中，看宫女手持黄绸扎制的莲花灯在阵中穿行，先至亭前者受赏，故又名&quot;黄花阵&quot;。如今的万花阵是1989年按原样复建的，是西洋楼景区内难得的可以&quot;走入其中&quot;体验的景观。</p><h3 id="养雀笼与方外观" tabindex="-1">养雀笼与方外观 <a class="header-anchor" href="#养雀笼与方外观" aria-label="Permalink to &quot;养雀笼与方外观&quot;">​</a></h3><p><strong>养雀笼</strong>为饲养孔雀等珍禽之所，券门两侧设铜丝笼架，昔日孔雀开屏于石券之间。<strong>方外观</strong>是乾隆为容妃（民间传说中的&quot;香妃&quot;）所建的礼拜之处，建筑西向，内部曾刻有阿拉伯文《古兰经》经文，是清代民族融合的一段见证。</p><h3 id="线法山与线法墙" tabindex="-1">线法山与线法墙 <a class="header-anchor" href="#线法山与线法墙" aria-label="Permalink to &quot;线法山与线法墙&quot;">​</a></h3><p>景区最东端为<strong>线法山</strong>与<strong>线法墙</strong>。&quot;线法&quot;即西洋透视画法：线法墙上曾张挂描绘欧洲街市、田园的巨幅透视画，皇帝立于特定视点望去，画景与实景连成一片，如身临其境——堪称18世纪的&quot;沉浸式&quot;视觉装置。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="乾隆的-西洋玩具" tabindex="-1">乾隆的&quot;西洋玩具&quot; <a class="header-anchor" href="#乾隆的-西洋玩具" aria-label="Permalink to &quot;乾隆的&quot;西洋玩具&quot;&quot;">​</a></h3><p>西洋楼的建造源于乾隆对欧洲水法的好奇。传教士蒋友仁献上的欧洲喷泉图样引起皇帝极大兴趣，遂命在长春园北垣辟地建造。乾隆常于午后驾临西洋楼，观赏大水法喷涌、走万花阵迷灯、在方外观小坐。</p><p>对他而言，西洋楼是&quot;天朝上国&quot;尽收天下奇巧的缩影——西方技艺在此被收纳为皇权的点缀。这种&quot;中体西用&quot;的姿态，恰是那个时代中西关系的微妙注脚。</p><h3 id="铜版画的最后影像" tabindex="-1">铜版画的最后影像 <a class="header-anchor" href="#铜版画的最后影像" aria-label="Permalink to &quot;铜版画的最后影像&quot;">​</a></h3><p>乾隆年间，宫廷委托制作**《圆明园西洋楼铜版图》**二十幅，以欧洲铜版蚀刻技法精细记录全景区面貌。这套铜版画成为西洋楼最完整的图像档案——1860年焚毁之后，后人正是依靠它复原想象当年的盛景。</p><p>如今园内多处展板即取自这套铜版画，是游客对照废墟、还原历史的最佳依据。1970年代后，中国学者依据铜版画与文献逐步清理复原遗址，1989年复建万花阵，2000年代起遗址区全面开放。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong><a href="/beijing-travel-guide/landmarks/yuanmingyuan/dashuifa.html">大水法</a>残柱阵</strong>：西洋楼主景，圆明园的标志性画面</li><li><strong><a href="/beijing-travel-guide/landmarks/yuanmingyuan/haiyan-tang.html">海晏堂</a>残墙与喷水池遗址</strong>：十二生肖兽首喷泉的原址</li><li><strong>万花阵迷宫</strong>：复建的花园迷阵，可亲身穿行，中心凉亭可小憩</li><li><strong>远瀛观石门与雕花石屏</strong>：西洋军旗甲胄纹样的石雕精品</li><li><strong>谐奇趣海棠形喷水池遗址</strong>：西洋楼最早的建筑遗存</li><li><strong>铜版画对照展板</strong>：每处遗址旁均设原貌图版，强烈建议逐一对照</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>西洋楼遗址区需在10元大门票之外<strong>另购15元门票</strong>，入口位于景区内三园交界处以北</li><li>建议自西向东游览：谐奇趣 → 万花阵 → 养雀笼 → 方外观 → 海晏堂 → 大水法 → 远瀛观 → 线法山，全程约2小时</li><li>遗址石构件均为文物，<strong>严禁攀爬、坐卧、触摸</strong></li><li>建议租语音导览或请讲解员：废墟若无背景知识，观感大打折扣</li><li>清晨开园即入或黄昏时段游览，光线最佳且游客稀少</li></ul><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a>——三园全貌与游览路线</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/dashuifa.html">大水法</a>——西洋楼主景喷泉遗址</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/haiyan-tang.html">海晏堂与十二生肖兽首</a>——兽首喷泉与国宝回归</li><li><a href="/beijing-travel-guide/history/yuanmingyuan-ruins.html">圆明园遗址历史专题</a>——西洋楼焚毁始末</li></ul><hr><p><strong>📍 位置</strong>：长春园北部，东西绵延约750米的狭长地带 <strong>⏱️ 建议游览</strong>：1.5-2小时 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a></p>',36)])])}const f=e(r,[["render",i]]);export{y as __pageData,f as default};
